import type { VolumeUnit } from "@/lib/mixing";
import { IconAlertTriangle } from "@/components/icons";

interface BatchPanelProps {
  volume: string;
  unit: VolumeUnit;
  error?: string;
  disabled: boolean;
  onVolumeChange: (value: string) => void;
  onUnitChange: (unit: VolumeUnit) => void;
}

export function BatchPanel({
  volume,
  unit,
  error,
  disabled,
  onVolumeChange,
  onUnitChange,
}: BatchPanelProps) {
  return (
    <fieldset disabled={disabled} className="min-w-0">
      <legend className="kicker mb-3">03 · Batch size</legend>
      <div className="grid items-start gap-4 sm:grid-cols-[minmax(0,1fr)_auto]">
        <div>
          <label htmlFor="batch-volume" className="label">
            Batch volume <span className="text-danger-600">*</span>
          </label>
          <input
            id="batch-volume"
            type="text"
            inputMode="decimal"
            autoComplete="off"
            placeholder="e.g. 10"
            className={`input max-w-[220px] font-mono ${error ? "input-invalid" : ""}`}
            value={volume}
            onChange={(e) => onVolumeChange(e.target.value)}
            aria-invalid={error ? true : undefined}
            aria-describedby={error ? "batch-volume-error" : "batch-volume-hint"}
          />
          {error ? (
            <p id="batch-volume-error" className="field-error">
              <IconAlertTriangle className="mt-px h-3 w-3 shrink-0" />
              {error}
            </p>
          ) : (
            <p id="batch-volume-hint" className="mt-1.5 text-xs text-ink-500">
              {unit === "L" ? "1 litre = 1,000 ml" : "1 US gallon = 3,785 ml"}
            </p>
          )}
        </div>

        <div>
          <span id="batch-unit-label" className="label">
            Unit
          </span>
          <div
            role="radiogroup"
            aria-labelledby="batch-unit-label"
            className="inline-flex overflow-hidden rounded-md border border-ink-300"
          >
            {(
              [
                { value: "L", label: "Litres" },
                { value: "gal", label: "US gal" },
              ] as const
            ).map((option) => {
              const active = unit === option.value;
              return (
                <label
                  key={option.value}
                  className={`relative cursor-pointer px-4 py-[10px] font-mono text-[13px] font-medium transition-colors ${
                    active ? "bg-ink-900 text-white" : "bg-white text-ink-600 hover:bg-ink-50"
                  }`}
                >
                  <input
                    type="radio"
                    name="batch-unit"
                    value={option.value}
                    checked={active}
                    onChange={() => onUnitChange(option.value)}
                    className="peer sr-only"
                  />
                  <span className="pointer-events-none absolute inset-0 outline-2 -outline-offset-2 outline-ink-900 peer-focus-visible:outline" />
                  {option.label}
                </label>
              );
            })}
          </div>
        </div>
      </div>
    </fieldset>
  );
}
