interface LogoProps {
  tone?: "light" | "dark";
}

/**
 * Logo lockup used in the application header.
 * tone "light" = light artwork for dark surfaces.
 */
export function Logo({ tone = "light" }: LogoProps) {
  const muted = tone === "light" ? "text-ink-300" : "text-ink-500";
  return (
    <div className="flex items-center gap-3">
      <LogoMark className={tone === "light" ? "h-9 w-9 text-white" : "h-9 w-9 text-ink-900"} />
      <div className="leading-none">
        <div className="flex items-center gap-2">
          <span className="font-display text-[17px] font-extrabold tracking-tight text-current">
            MixStation
          </span>
          <span
            className={`chip border ${
              tone === "light"
                ? "border-ink-600 text-ink-200"
                : "border-ink-300 text-ink-600"
            }`}
          >
            PRO
          </span>
        </div>
        <p
          className={`mt-1 font-mono text-[10px] uppercase tracking-[0.18em] ${muted}`}
        >
          Paint Mixing Calculator
        </p>
      </div>
    </div>
  );
}
