import { IconAlertTriangle, IconCheck, IconInfo, IconX } from "@/components/icons";

export interface ToastData {
  id: number;
  kind: "success" | "error" | "info";
  message: string;
}

interface ToastProps {
  toast: ToastData | null;
  onDismiss: () => void;
}

export function Toast({ toast, onDismiss }: ToastProps) {
  if (!toast) return null;

  const accent =
    toast.kind === "success"
      ? "border-l-success-600"
      : toast.kind === "error"
        ? "border-l-danger-600"
        : "border-l-ink-700";

  const icon =
    toast.kind === "success" ? (
      <IconCheck className="h-4 w-4 text-success-600" />
    ) : toast.kind === "error" ? (
      <IconAlertTriangle className="h-4 w-4 text-danger-600" />
    ) : (
      <IconInfo className="h-4 w-4 text-ink-700" />
    );

  return (
    <div
      role="status"
      aria-live="polite"
      className="fixed bottom-6 right-6 z-50 max-w-sm"
    >
      <div
        key={toast.id}
        className={`toast-enter card flex items-start gap-3 border-l-4 p-4 shadow-lg ${accent}`}
      >
        <span className="mt-0.5 shrink-0">{icon}</span>
        <p className="text-sm font-medium leading-snug text-ink-900">{toast.message}</p>
        <button
          type="button"
          onClick={onDismiss}
          aria-label="Dismiss notification"
          className="ml-2 shrink-0 rounded p-1 text-ink-400 transition-colors hover:bg-ink-100 hover:text-ink-700 focus-visible:outline-2 focus-visible:outline-offset-1 focus-visible:outline-ink-900"
        >
          <IconX className="h-3.5 w-3.5" />
        </button>
      </div>
    </div>
  );
}
